$(function () {
    let formCekEdit; // global untuk tracking

    // Pasang csrf token untuk semua permintaan ajax
    $.ajaxSetup({
        headers: {
            "X-CSRF-TOKEN": $('meta[name="csrf-token"]').attr("content"),
        },
    });

    // Buka tutup input password
    $(document).on("click", ".toggle-password", function () {
        let $allInputs = $(
            "input[type='password'], input[type='text'][data-password='true']"
        );

        if ($allInputs.first().attr("type") === "password") {
            // ubah semua jadi text
            $allInputs.attr("type", "text").attr("data-password", "true");
            $(".toggle-password i")
                .removeClass("bi-eye-fill")
                .addClass("bi-eye-slash-fill");
        } else {
            // ubah semua jadi password
            $allInputs.attr("type", "password");
            $(".toggle-password i")
                .removeClass("bi-eye-slash-fill")
                .addClass("bi-eye-fill");
        }
    });

    // Fungsi load statisik user
    function loadStats() {
        $.get(window.routes.statisticUser, function (res) {
            $(".stat-value").each(function () {
                let key = $(this).data("key");
                if (res[key] !== undefined) {
                    $(this).text(res[key]);
                }
            });
            $(".overlay.dark").fadeOut();
        });
    }

    // Tambah user
    $("#formAddUser").validate(
        $.extend(FormHelper.validasiForm(), {
            rules: {
                name: { required: true, minlength: 3, maxlength: 30 },
                email: { required: true, email: true, customEmail: true },
                password: { required: true, minlength: 8 },
                password_confirmation: {
                    required: true,
                    equalTo: "#formAddUser input[name='password']",
                },
                perusahaan: { minlength: 3, maxlength: 30 },
                whatsapp: { number: true, minlength: 8, maxlength: 15 },
                telegram: { number: true, minlength: 8, maxlength: 15 },
                alamat: { minlength: 5, maxlength: 100 },
            },
            submitHandler: function (form) {
                let $btnSubmit = $(form).find("button[type=submit]");
                let $btnCancle = $(form).find(".btn-danger");
                let $btnLoading = $(form).find("#btn-loading");

                $btnSubmit.hide();
                $btnCancle.hide();
                $btnLoading.show();

                $.ajax({
                    url: $(form).attr("action"),
                    type: "POST",
                    data: $(form).serialize(),
                    success: function (res) {
                        if (res.success) {
                            $("#modalAddUser").modal("hide");
                            $("#tableUserList").DataTable().ajax.reload();
                            Swal.fire("Sukses", res.message, "success");
                            $(form)[0].reset();
                            $(form).validate().resetForm();
                            $(form).find(".is-valid").removeClass("is-valid");

                            loadStats();
                        }
                    },
                    error: function (xhr) {
                        if (xhr.status === 422) {
                            let errors = xhr.responseJSON.errors;
                            if (errors) {
                                $(form).validate().showErrors(errors);
                            }
                        }

                        Swal.fire(
                            "Validasi Gagal!",
                            "Silahkan periksa kembali input Anda",
                            "error"
                        );
                    },
                    complete: function () {
                        $btnLoading.hide();
                        $btnSubmit.show();
                        $btnCancle.show();
                    },
                });
                return false;
            },
        })
    );

    // Ubah User
    $("#formEditUser").validate(
        $.extend(FormHelper.validasiForm(), {
            rules: {
                name: { required: true, minlength: 3, maxlength: 30 },
                email: { required: true, email: true, customEmail: true },
                password: { minlength: 8 },
                password_confirmation: {
                    equalTo: "#formEditUser input[name='password']",
                },
                perusahaan: { minlength: 3, maxlength: 30 },
                whatsapp: { number: true, minlength: 8, maxlength: 15 },
                telegram: { number: true, minlength: 8, maxlength: 15 },
                alamat: { minlength: 5, maxlength: 100 },
            },
            submitHandler: function (form) {
                let $btnSubmit = $(form).find("button[type=submit]");
                let $btnCancle = $(form).find(".btn-danger");
                let $btnLoading = $(form).find("#btn-loading");

                // cek perubahan
                if (formCekEdit && !formCekEdit.isChanged()) {
                    return false;
                }

                $btnSubmit.hide();
                $btnCancle.hide();
                $btnLoading.show();

                $.ajax({
                    url: $(form).attr("action"),
                    type: "POST",
                    data: $(form).serialize(),
                    success: function (res) {
                        if (res.success) {
                            $("#modalEditUser").modal("hide");
                            $("#tableUserList").DataTable().ajax.reload();
                            Swal.fire("Sukses", res.message, "success");
                            $(form)[0].reset();
                            $(form).validate().resetForm();
                            $(form).find(".is-valid").removeClass("is-valid");

                            loadStats();
                        }
                    },
                    error: function (xhr) {
                        if (xhr.status === 422) {
                            let errors = xhr.responseJSON.errors;
                            if (errors) {
                                $(form).validate().showErrors(errors);
                            }
                        }

                        Swal.fire(
                            "Validasi Gagal!",
                            "Silahkan periksa kembali input Anda",
                            "error"
                        );
                    },
                    complete: function () {
                        $btnLoading.hide();
                        $btnSubmit.show();
                        $btnCancle.show();
                    },
                });
                return false;
            },
        })
    );

    // Ambil user berdasarkan id
    $(document).on(
        "click",
        '#tableUserList button[data-target="#modalEditUser"]',
        function () {
            let id = $(this).data("id");
            let url = window.routes.getUser.replace(":id", id);
            let $form = $("#formEditUser");

            $.get(url)
                .done(function (res) {
                    let user = res.user;

                    $form[0].reset();
                    $form.validate().resetForm();
                    $form
                        .find(".is-valid, .is-invalid")
                        .removeClass("is-valid is-invalid");

                    $form.attr(
                        "action",
                        window.routes.updateUser.replace(":id", id)
                    );

                    $("#edit_name").val(user.name);
                    $("#edit_email").val(user.email);
                    $("#edit_aktivasi").val(user.active ? "Aktif" : "Nonaktif");
                    $("#edit_role").val(user.role);
                    $("#edit_password, #edit_password_confirmation").val("");

                    if (user.profile) {
                        $("#edit_perusahaan").val(
                            user.profile.perusahaan || ""
                        );
                        $("#edit_whatsapp").val(user.profile.whatsapp || "");
                        $("#edit_telegram").val(user.profile.telegram || "");
                        $("#edit_alamat").val(user.profile.alamat || "");
                    } else {
                        $(
                            "#edit_perusahaan, #edit_whatsapp, #edit_telegram, #edit_alamat"
                        ).val("");
                    }

                    $("#modalEditUser").modal("show");

                    // reset tracker perubahan form
                    formCekEdit = FormHelper.cekFormData("#formEditUser");
                })
                .fail(function (xhr) {
                    // ambil pesan error dari response JSON (misalnya dari handleException)
                    let message =
                        (xhr.responseJSON && xhr.responseJSON.message) ||
                        "Terjadi kesalahan saat mengambil data user.";

                    // tampilkan SweetAlert error
                    Swal.fire({
                        icon: "error",
                        title: "Gagal memuat data!",
                        text: message,
                    });
                });
        }
    );


    // Inisialisasi data tabel
    $("#tableUserList").DataTable(TableHelper.dynamicTable);

    // Panggil statistik user saat halaman dimuat
    loadStats();
});

const TableHelper = {
    dynamicTable: {
        ajax: window.routes.dataTable,
        paging: true,
        searching: true,
        ordering: true,
        info: true,
        autoWidth: false,
        responsive: true,
        processing: true,
        serverSide: false,
        order: [[1, "asc"]],
        columns: [
            {
                data: "id",
                className: "dt-head-center dt-body-center",
                title: "ID",
                orderable: true,
            },
            {
                data: "name",
                className: "dt-head-center",
                title: "Nama User",
                orderable: true,
            },
            {
                data: "email",
                className: "dt-head-center",
                title: "Alamat Email",
                orderable: false,
            },
            {
                data: "status",
                className: "dt-head-center dt-body-center col-status",
                title: "Status",
                orderable: true,
                render: {
                    _: function (data) {
                        return data ? "Aktif" : "Non aktif";
                    },
                    display: function (data) {
                        return data
                            ? '<span class="lencana bg-primary">Aktif</span>'
                            : '<span class="lencana bg-danger">Non aktif</span>';
                    },
                },
            },
            {
                data: "role",
                className: "dt-head-center dt-body-center",
                title: "Hak Akses",
                orderable: true,
            },
            {
                data: "last_login_at",
                className: "dt-head-center dt-body-center",
                title: "Terakhir Aktif",
                render: (data, type) =>
                    TableHelper.tabelTanggalWaktu(data, type),
                orderable: false,
                searchable: false,
            },
            {
                data: "created_at",
                className: "dt-head-center dt-body-center",
                title: "Waktu Dibuat",
                render: (data, type) =>
                    TableHelper.tabelTanggalWaktu(data, type),
                orderable: false,
                searchable: false,
            },
            {
                data: "updated_at",
                className: "dt-head-center dt-body-center",
                title: "Waktu Diubah",
                render: (data, type) =>
                    TableHelper.tabelTanggalWaktu(data, type),
                orderable: false,
                searchable: false,
            },
            {
                data: null,
                orderable: false,
                searchable: false,
                className: "dt-head-center dt-body-center",
                title: "Aksi",
                render: function (data, type, row) {
                    if (type === "display") {
                        return `
                            <div class="btn-group" role="group">
                                <button class="btn btn-sm btn-dark btn-edit" data-id="${row.id}" data-toggle="modal" data-target="#modalEditUser">Edit</button>
                                <button class="btn btn-sm btn-success btn-profile" data-id="${row.id}">Profil</button>
                            </div>`;
                    }
                    return "";
                },
            },
        ],
        dom: `
            <"row mb-2"<"col-sm-2"B><"col-sm-2"l><"col-sm-8"f>>
            <"row"<"col-sm-12"tr>>
            <"row mt-2"<"col-sm-5"i><"col-sm-7"p>>
        `,
        buttons: {
            dom: {
                container: {
                    className: "dt-buttons",
                },
                button: {
                    className: "dt-button btn btn-sm",
                },
            },
            buttons: [
                {
                    text: "Add",
                    attr: {
                        "data-target": "#modalAddUser",
                        "data-toggle": "modal",
                    },
                },
                {
                    text: "Excel",
                },
            ],
        },
        initComplete: function () {
            let api = this.api();
            // cari container filter sesuai ID DataTable kamu (otomatis: #tableUserList_filter)
            let filterContainer = $("#tableUserList_filter");
            let extraFilters = $('<div class="ml-2 d-inline-block"></div>');

            // misalnya tambahin dropdown filter utk kolom Status (index 3) dan Role (index 4)
            api.columns([3, 4]).every(function () {
                let column = this;
                let headerText = $(column.header()).text().trim();
                let select = $(
                    '<select class="form-control form-control-sm d-inline-block w-auto mr-1">' +
                        '<option value="">Semua ' +
                        headerText +
                        "</option></select>"
                )
                    .appendTo(extraFilters)
                    .on("change", function () {
                        let val = $.fn.dataTable.util.escapeRegex(
                            $(this).val()
                        );
                        column
                            .search(val ? "^" + val + "$" : "", true, false)
                            .draw();
                    });

                column
                    .cells(null, column.index(), { search: "applied" })
                    .render("display")
                    .unique()
                    .sort()
                    .each(function (d) {
                        let text = $("<div>").html(d).text().trim();
                        if (text.length) {
                            select.append(
                                '<option value="' +
                                    text +
                                    '">' +
                                    text +
                                    "</option>"
                            );
                        }
                    });
            });

            filterContainer.append(extraFilters);
        },
    },

    /**
     * Fungsi render untuk kolom Tanggal dan Waktu di DataTables.
     * Bergantung pada fungsi formatTanggal dari FormatHelper.
     * Contoh penggunaan: { targets: [6, 7], render: TabelHelper.tabelTanggalWaktu }
     */
    tabelTanggalWaktu: function (data, type) {
        if (!data) return "-";
        if (type !== "display") return data;
        const [tanggal, waktu] = data.split(" ");
        const formattedTanggal = FormatHelper.formatTanggal(tanggal);
        return `${formattedTanggal} → ${waktu || ""}`;
    },
};
